import React from 'react';
import type { ColorPickerBaseProps } from '../type';
import { ColorPickerProvider, useColorPicker } from '../ColorPickerContext';

import '../style';

export const PrimitiveColorPicker: React.FC<ColorPickerBaseProps> = props => {
  const { children } = props;
  const colorPickerCtx = useColorPicker(props);

  return <ColorPickerProvider value={colorPickerCtx}>{children}</ColorPickerProvider>;
};
